INSERT INTO `application_settings` VALUES (1,'Sidebar Collapse','sidebar-collapse','switch','0',NULL,NULL,1,NULL,28,'2023-12-27 01:15:51','2024-01-19 08:55:41'),(2,'Logo','logo','file','logo_sx6aea3lu.png','Maharaja Logo',NULL,2,NULL,20,'2023-12-27 01:15:51','2024-01-19 08:55:41'),(3,'Site Name','site-name','textbox','Maharaja Indian Cuisine',NULL,NULL,2,NULL,21,'2023-12-27 01:15:51','2024-03-29 06:35:11'),(4,'Primary Phone Number','primary-phone-number','textbox','+1 402-505-4488',NULL,NULL,3,NULL,22,'2023-12-27 01:29:19','2026-05-04 14:58:11'),(5,'Secondary Phone Number','secondary-phone-number','textbox',NULL,NULL,NULL,3,NULL,23,'2023-12-27 01:30:28','2024-01-19 08:55:41'),(6,'Primary Mail','primary-mail','textbox','maharaja.oma@gmail.com',NULL,NULL,3,NULL,24,'2023-12-27 01:31:54','2024-01-19 08:55:41'),(7,'Secondary Email','secondary-email','textbox','maharaja.oma@gmail.com',NULL,NULL,3,NULL,25,'2023-12-27 01:31:54','2025-06-30 09:54:44'),(9,'Primay Color','primay-color','color','#C82E26',NULL,NULL,2,NULL,26,'2023-12-28 06:33:41','2024-01-31 06:36:04'),(11,'Secondary Color','secondary-color','color','#E6B22B',NULL,NULL,2,NULL,27,'2023-12-29 00:22:47','2024-01-19 08:55:41'),(12,'Contact Address','contact-address','textarea','<p>617 N 114 St Omaha, NE 68154, United States </p>',NULL,NULL,3,NULL,19,'2024-01-09 23:12:30','2026-05-04 16:08:49'),(13,'Hours of Operation','hours-of-operation','textarea','<ul>\r\n	<li><span>Monday to Sunday </span>: 11:00 AM to 9:00 PM</li>\r\n</ul>',NULL,NULL,3,NULL,29,'2024-01-19 07:13:02','2026-05-04 17:35:22'),(14,'Footer Contact','footer-contact','heading',NULL,NULL,NULL,3,NULL,30,'2024-01-19 07:14:19','2024-01-19 08:55:41'),(15,'Footer Contact Map Iframe','footer-contact-map-iframe','textarea','<p><iframe allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\" src=\"https://www.google.com/maps/embed?pb=!1m14!1m8!1m3!1d11996.15938722899!2d-96.0902312!3d41.2644683!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x8793f295c4fbdd5d%3A0xacabaa4eb1b9249!2sMaharaja%20Indian%20Cuisine!5e0!3m2!1sen!2sin!4v1705754191235!5m2!1sen!2sin\" style=\"border:0;\" width=\"100%\"></iframe></p>',NULL,NULL,3,NULL,31,'2024-01-19 07:15:05','2024-01-20 12:37:52'),(16,'Footer Contact Short Description','footer-contact-short-description','textarea','<p><span class=\"small-title\">Get in touch</span></p>\r\n<h3>VISIT MAHARAJA INDIAN CUISINE</h3>\r\n<p>Where Authenticity Meets Exquisite Taste!</p>',NULL,NULL,3,NULL,32,'2024-01-19 07:16:41','2026-05-04 16:11:44'),(17,'Opening Hours','opening-hours','textarea-normal','Monday to Sunday - 11:00 AM to 9:00 PM<br/>',NULL,NULL,3,NULL,33,'2024-01-19 07:17:55','2026-05-05 03:04:17'),(18,'Map Location','map-location','textarea','<p>617 N 114th St, Omaha, NE 68154, United States</p>',NULL,NULL,3,NULL,34,'2024-01-19 07:19:01','2024-01-19 08:55:41'),(19,'Welcome','welcome','heading',NULL,NULL,NULL,4,NULL,1,'2024-01-19 07:22:39','2024-01-19 08:55:41'),(20,'Welcome Title','welcome-title','textbox','Maharaja Indian Restaurant <span>Where every dish is a royal treat!</span>',NULL,NULL,4,NULL,2,'2024-01-19 07:24:13','2024-01-19 08:55:41'),(21,'Welcome Description','welcome-description','textarea','<p class=\"lead\">For over a decade, Maharaja has been your first choice when it comes to Indian cuisine. Discover a delicious blend of classic dishes and thali experiences that are designed to highlight the diversity of our cuisine. Put your trust in Maharaja to take you on a delicious adventure that combines tradition with an unforgettable meal around every corner.</p>',NULL,NULL,4,NULL,3,'2024-01-19 07:27:37','2024-07-30 10:17:14'),(22,'Welcome Button Text','welcome-button-text','textbox','KNOW MORE',NULL,NULL,4,NULL,4,'2024-01-19 07:29:20','2024-01-30 13:48:50'),(23,'Welcome Button URL','welcome-button-url','textbox','about-us',NULL,NULL,4,NULL,5,'2024-01-19 07:29:45','2024-01-31 17:36:23'),(24,'Welcome Gallery','welcome-gallery','multiple-files','[{\"path\":\"Screenshot-2025-10-05-at-3.55.50\\u202fAM_16ywy3bxg.png\",\"alt_text\":\"Traditional restaurant in Omaha\"},{\"path\":\"4EP_Maharaja-121_so3ycwibi.jpg\",\"alt_text\":\"Indian food restaurant at omaha\"},{\"path\":\"4EP_Maharaja-131_nniwpmns9.jpg\",\"alt_text\":\"Indian restaurant in Omaha\"},{\"path\":\"4EP_Maharaja-119_kq66i3pqo.jpg\",\"alt_text\":\"Restaurant in Omaha\"}]',NULL,NULL,4,NULL,6,'2024-01-19 07:38:01','2025-10-04 22:35:27'),(25,'CLASSIC VINTAGE','classic-vintage','heading',NULL,NULL,NULL,4,NULL,7,'2024-01-19 07:38:20','2024-01-19 08:55:41'),(26,'Classic Vintage Title','classic-vintage-title','textbox','CLASSIC & VINTAGE',NULL,NULL,4,NULL,8,'2024-01-19 07:38:41','2024-01-19 08:55:41'),(27,'Classic Vintage Description','classic-vintage-description','textarea','<p>Step back in time with Maharaja\'s classic and vintage dishes. Our special menu offers traditional Indian flavors in simple, delicious bites. From tasty curries to sweet treats, each dish brings the essence of old-fashioned traditional cooking at Maharaja!</p>',NULL,NULL,4,NULL,9,'2024-01-19 07:39:14','2024-07-30 10:17:14'),(28,'Classic Vintage Image 1','classic-vintage-image-1','file','4EP_Maharaja-080_a9yiaxyaw.jpg','Classic Vintage Image',NULL,4,NULL,10,'2024-01-19 07:41:02','2025-10-04 21:03:26'),(29,'Classic Vintage Image 2','classic-vintage-image-2','file','Screenshot-2025-10-05-at-2.36.22 AM_evw8ba1wy.png','Classic Vintage Image',NULL,4,NULL,11,'2024-01-19 07:41:15','2025-10-04 21:08:33'),(30,'Classic Vintage Image 3','classic-vintage-image-3','file','4EP_Maharaja-035-(1)_lha1d4wyu.jpg','Classic Vintage Image',NULL,4,NULL,13,'2024-01-19 07:41:31','2025-10-04 22:18:37'),(31,'Classic Vintage Image 4','classic-vintage-image-4','file','4EP_Maharaja-018_g5nerke49.jpg','Classic Vintage Image',NULL,4,NULL,12,'2024-01-19 07:41:47','2025-10-04 21:28:34'),(32,'Metricool Script','metricool-script','textarea','<p><script>function loadScript(a){var b=document.getElementsByTagName(\"head\")[0],c=document.createElement(\"script\");c.type=\"text/javascript\",c.src=\"https://tracker.metricool.com/resources/be.js\",c.onreadystatechange=a,c.onload=a,b.appendChild(c)}loadScript(function(){beTracker.t({hash:\"72e2e8cbdf7cceb01a9033a3f908b146\"})});</script></p>',NULL,NULL,2,NULL,14,'2024-01-19 08:45:02','2024-03-30 07:19:24'),(33,'OPEN EVERYDAY Title','open-everyday-title','textbox','Book Your Table Today!',NULL,NULL,4,NULL,15,'2024-01-19 08:49:51','2024-02-08 02:31:04'),(34,'OPEN EVERYDAY Description','open-everyday-description','textarea','<p>Experience the flavors of <br>\r\nour exquisite cuisine served <br>\r\n<b>Monday</b> through <b>Sunday</b><br> \r\nfrom <b>11AM to 9PM</b></p>',NULL,NULL,4,NULL,16,'2024-01-19 08:50:05','2025-07-19 04:23:12'),(35,'OPEN EVERYDAY Button','open-everyday-button','textbox','Make Reservation',NULL,NULL,4,NULL,17,'2024-01-19 08:50:21','2024-01-19 08:55:41'),(36,'OPEN EVERYDAY URL','open-everyday-url','textbox','402-505-4488',NULL,NULL,4,NULL,18,'2024-01-19 08:50:42','2024-01-29 10:38:18'),(37,'Get your favourite Title','get-your-favourite-title','textbox','Get your favourite Indian Food Delivered home',NULL,NULL,4,NULL,NULL,'2024-01-19 08:56:22','2024-01-19 08:58:46'),(38,'Get your favourite Button','get-your-favourite-button','textbox','ORDER NOW',NULL,NULL,4,NULL,NULL,'2024-01-19 08:56:52','2024-02-01 07:02:51'),(39,'Get your favourite Button Url','get-your-favourite-button-url','textbox','https://maharajaindiancuisine.hungerrush.com/Order/OrderType',NULL,NULL,4,NULL,NULL,'2024-01-19 08:57:00','2026-02-11 08:13:13'),(40,'Get your favourite Descriptiion','get-your-favourite-descriptiion','textarea','<p>You can get your favourite Biryani, Butter Chicken or Kadhai Paneer delivered to your doorsteps. Order online now with ease!</p>',NULL,NULL,4,NULL,NULL,'2024-01-19 08:57:40','2024-01-19 08:58:46'),(41,'From Small to Large','from-small-to-large','heading',NULL,NULL,NULL,4,NULL,NULL,'2024-01-19 09:00:20','2024-01-19 09:00:20'),(42,'From Small to Large Title','from-small-to-large-title','textbox','From Small to Large Party Orders',NULL,NULL,4,NULL,NULL,'2024-01-19 09:00:35','2024-01-19 09:01:33'),(43,'From Small to Large Description','from-small-to-large-description','textarea','<p>Maharaja caters to all occasions, bringing the authentic flavors of India to your gatherings, conferences, celebrations, and more!</p>\r\n\r\n<ul>\r\n	<li>Warm welcome gatherings</li>\r\n	<li>Business conferences</li>\r\n	<li>Celebration gathering</li>\r\n	<li>Formal gatherings</li>\r\n	<li>Radiant Receptions</li>\r\n	<li>Small-scale gathering</li>\r\n</ul>',NULL,NULL,4,NULL,NULL,'2024-01-19 09:00:48','2024-02-01 07:48:52'),(44,'From Small to Large Gallery','from-small-to-large-gallery','multiple-files','[{\"path\":\"side-view-people-celebrating-tamil-new-year_23-2151210764_pbh411ur8.webp\",\"alt_text\":\"Indian Traditional Food in Omaha\"},{\"path\":\"happy-family-havinf-dinner-together_dozopg4hg.webp\",\"alt_text\":\"Omaha Venue\"},{\"path\":\"extra-(1)_j0y6t4j6k_bna9wd6gz.webp\",\"alt_text\":\"Delicious food items in Omaha\"}]',NULL,NULL,4,NULL,NULL,'2024-01-19 09:01:05','2024-03-07 18:41:25'),(46,'Order Now Text','order-now-text','textbox','Order Now',NULL,NULL,2,NULL,NULL,'2024-01-20 09:48:50','2024-11-29 09:29:38'),(47,'Order Now URL','order-now-url','textbox','https://maharajaindiancuisine.hungerrush.com/Order/OrderType',NULL,NULL,2,NULL,NULL,'2024-01-20 09:49:04','2026-02-11 08:17:11'),(48,'facebook','facebook','textbox','https://www.facebook.com/profile.php?id=100044680852133',NULL,NULL,3,NULL,NULL,'2024-01-20 10:11:02','2024-02-15 12:09:50'),(49,'twitter','twitter','textbox','https://twitter.com/maharajaindi',NULL,NULL,3,NULL,NULL,'2024-01-20 10:11:15','2024-03-30 07:45:32'),(50,'instagram','instagram','textbox','https://www.instagram.com/maharaja_indiancuisine/',NULL,NULL,3,NULL,NULL,'2024-01-20 10:11:28','2024-02-15 12:09:51'),(51,'doordash','doordash','textbox','https://www.doordash.com/',NULL,NULL,3,NULL,NULL,'2024-01-20 10:11