INSERT INTO `cms` VALUES (3,'Our Menu','our-menu','root','customurl','/our-menu',NULL,NULL,NULL,NULL,NULL,NULL,'[]',1,0,0,1,'Explore Our Indian Menu | Best Indian Restaurant in Omaha','indian food omaha, indian menu omaha, food near me, best restaurants omaha','Browse the Maharaja Indian Cuisine menu — tandoori, curries, and biryanis made fresh daily.',1,3,'2023-12-27 03:26:00','2025-08-18 11:32:59'),(5,'About Us','about-us','root','pageview',NULL,NULL,NULL,NULL,NULL,NULL,'<section class=\"about-page\">\r\n<div class=\"container\">\r\n<div class=\"row align-items-center justify-content-around  about-page-top\">\r\n<div class=\"col-md-4 \"><img class=\"rounded shadow-3d img-fluid w-100\" src=\"../../../images/media/4EP_Maharaja-049-min-(1)_ltz9fbkh4.jpg\" alt=\"Traditional Indian food image\"></div>\r\n<div class=\"col-md-7\">\r\n<h2 class=\"section-title\">Traditional Indian Food in Omaha</h2>\r\n<p>Welcome to Maharaja, where we\'ve been proudly serving authentic Indian cuisine for over a decade. Nestled in the heart of Omaha, our restaurant offers a culinary journey that celebrates the vibrant tapestry of Indian flavors and culinary traditions.</p>\r\n<p>At Maharaja, we invite you to explore our menu, meticulously crafted to showcase the diverse range of dishes from our culinary heritage.&nbsp;Whether you\'re craving something traditional or eager to explore something new, Maharaja promises an unforgettable dining experience that delights the senses and nourishes the soul.&nbsp;</p>\r\n<a class=\"smooth-scroll btn  btn-secondary\" title=\"Exploring biryani bliss at Omaha\'s Maharaja Indian Cuisine\" href=\"https://www.lozafina.com/community/explore-biryani-bliss-at-omahas-maharaja-indian-cuisine\" aria-label=\"Read more about exploring biryani bliss at Omaha\'s Maharaja Indian Cuisine\">Know More</a></div>\r\n</div>\r\n</div>\r\n</section>','[]',1,0,0,1,'Learn About Maharaja Indian Cuisine | Best Indian Restaurant Omaha','authentic indian restaurant omaha, indian food omaha, indian restaurants near me, best food omaha','Find Maharaja Indian Cuisine, a family-run Indian restaurant in Omaha serving authentic flavors. Your go-to spot for “Indian restaurants near Omaha.',1,2,'2023-12-28 06:17:20','2025-10-04 22:38:33'),(6,'Contact','contact','root','customurl','/contact',NULL,NULL,NULL,NULL,NULL,NULL,'[]',1,0,0,1,'Contact Maharaja Indian Cuisine – Indian Restaurant in Omaha','indian restaurant omaha, restaurants in omaha, food near me open now','Visit Maharaja Indian Cuisine in Omaha today. Get directions, view hours, or call to place an order. Conveniently located for locals and travelers searching for restaurants near me open now or the best Indian food nearby.',1,5,'2023-12-28 06:17:46','2025-08-18 11:38:13'),(7,'Blog','blog','root','pageview',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'[]',1,0,0,1,'Indian Food Blog – Maharaja Indian Cuisine Omaha','indian food omaha, places to eat omaha, best restaurants omaha','Read our Indian food blog for cooking tips, spice insights, and Omaha dining recommendations. Maharaja Indian Cuisine is a trusted guide for anyone searching for Indian restaurants nearby, places to eat in Omaha, or the best Indian food nearby.',1,6,'2024-01-29 11:37:01','2025-08-18 11:41:43'),(8,'Home','home','root','customurl','/home',NULL,NULL,NULL,NULL,NULL,NULL,'[]',0,0,0,0,'Best Indian Food in Omaha | Maharaja Indian Cuisine Restaurant','indian restaurant in omaha, indian food omaha, best indian cuisine omaha, restaurants near me, places to eat omaha','Craving Indian food in Omaha? Visit Maharaja Indian Cuisine for rich curries, fresh naan, and flavorful spices',1,1,'2024-03-19 11:52:46','2025-08-18 11:28:42'),(9,'Sitemap.xml','sitemapxml','root','pageview',NULL,NULL,NULL,NULL,NULL,NULL,'<div style=\"background: #000; color: #fff; padding: 5px; font: 14px \'Arial\', Tahoma, sans-serif; min-height: 100%;\">\r\n<table style=\"width: 80%; margin: 0 auto;\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: .5em;\" colspan=\"4\"><a style=\"display: block; padding: .5em; font-size: 1em; text-decoration: none; color: #fff; border: 1px solid #ccc; border-radius: 3px; background: #333; text-align: center;\" href=\"../../../\">Home page</a></td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: .5em;\" colspan=\"1\"><a style=\"display: block; padding: .5em; font-size: 1em; text-decoration: none; color: #fff; border: 1px solid #ccc; border-radius: 3px; background: #333; text-align: center;\" href=\"../../../our-menu\">Our Menu</a></td>\r\n<td style=\"padding: .5em;\" colspan=\"1\"><a style=\"display: block; padding: .5em; font-size: 1em; text-decoration: none; color: #fff; border: 1px solid #ccc; border-radius: 3px; background: #333; text-align: center;\" href=\"../../../about-us\">About Us</a></td>\r\n<td style=\"padding: .5em;\" colspan=\"1\"><a style=\"display: block; padding: .5em; font-size: 1em; text-decoration: none; color: #fff; border: 1px solid #ccc; border-radius: 3px; background: #333; text-align: center;\" href=\"../../../contact\">Contact</a></td>\r\n<td style=\"padding: .5em;\" colspan=\"1\"><a style=\"display: block; padding: .5em; font-size: 1em; text-decoration: none; color: #fff; border: 1px solid #ccc; border-radius: 3px; background: #333; text-align: center;\" href=\"../../../blog/what-stories-do-our-dishes-tell\">Blog</a></td>\r\n</tr>\r\n<tr>\r\n<td colspan=\"1\"><!-- Empty cell under Our Menu --></td>\r\n<td colspan=\"1\"><!-- Empty cell under Our Menu --></td>\r\n<td colspan=\"1\"><!-- Empty cell under Our Menu --></td>\r\n<td style=\"padding-top: 1em;\" colspan=\"1\"><a style=\"display: block; padding: .5em; font-size: 1em; text-decoration: none; color: #fff; border: 1px solid #ccc; border-radius: 3px; background: #333;\" href=\"../../../blog/what-stories-make-our-signature-dishes-truly-unforgettable\">Best signature dish</a></td>\r\n</tr>\r\n<tr>\r\n<td colspan=\"1\"><!-- Empty cell under Our Menu --></td>\r\n<td colspan=\"1\"><!-- Empty cell under Our Menu --></td>\r\n<td colspan=\"1\"><!-- Empty cell under Our Menu --></td>\r\n<td colspan=\"1\"><a style=\"display: block; padding: .5em; font-size: 1em; text-decoration: none; color: #fff; border: 1px solid #ccc; border-radius: 3px; background: #333;\" href=\"../../../blog/looking-for-a-taste-of-royalty-in-omaha-who-else-but-maharaja\">Taste of royalty</a></td>\r\n</tr>\r\n<tr>\r\n<td colspan=\"1\"><!-- Empty cell under Our Menu --></td>\r\n<td colspan=\"1\"><!-- Empty cell under Our Menu --></td>\r\n<td colspan=\"1\"><!-- Empty cell under Our Menu --></td>\r\n<td colspan=\"1\"><a style=\"display: block; padding: .5em; font-size: 1em; text-decoration: none; color: #fff; border: 1px solid #ccc; border-radius: 3px; background: #333;\" href=\"../../../blog/do-you-like-our-chicken-tikka-masala-checkout-our-other-chefs-recommendations\">Chicken Tikka Masala Dish</a></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>','[]',0,0,0,0,'Website Sitemap | Maharaja Indian Cuisine in Omaha','sitemap omaha restaurant, maharaja indian cuisine sitemap, indian food omaha website map','View the full sitemap of Maharaja Indian Cuisine in Omaha to quickly access our homepage, menu, order online, catering, and contact pages. Perfect for easy navigation and indexing.',1,10,'2024-04-16 10:58:13','2025-08-18 11:43:47'),(11,'Catering','catering','root','pageview',NULL,NULL,NULL,NULL,NULL,NULL,'<div class=\"container\">\r\n<div class=\"row align-items-center justify-content-around  about-page-top\">\r\n<div class=\"col-md-4 \"><img class=\"rounded shadow-3d img-fluid w-100\" src=\"../../images/media/20240622_210906_rwn09ytj2.jpg\" alt=\"Traditional Indian food image\"></div>\r\n<div class=\"col-md-7\">\r\n<h2 class=\"section-title text-primary\">Experience the Magic of Maharaja Indian Cuisine</h2>\r\n<p>Looking for exceptional catering services that bring the rich and authentic flavors of India to your events? Maharaja Indian Cuisine offers an unparalleled dining experience tailored to your needs. Whether you\'re hosting a corporate event, wedding, birthday party, or private gathering, our catering service ensures a menu and presentation that impresses every guest.</p>\r\n<p>Our catering menu features a wide variety of North and South Indian dishes to satisfy every palate. If you have a special dish or recipe in mind, share your ideas with us! We&rsquo;re happy to collaborate and create a menu that reflects your unique preferences and makes your event truly remarkable.</p>\r\n</div>\r\n</div>\r\n</div>','[]',1,0,0,0,'Indian Catering Services | Authentic Indian Food in Omaha','catering omaha, indian food omaha, takeout omaha, restaurants near me','Make your next event memorable with authentic Indian catering from Maharaja Indian Cuisine in Omaha. Whether it’s a family gathering or corporate event, we’re a trusted choice for those looking for catering near Omaha or high-quality takeout.',1,4,'2024-07-30 08:54:37','2025-08-18 11:37:15'),(12,'order online','order-online','root','pageview',NULL,NULL,NULL,'Thanks Giving Day!',NULL,NULL,'<div class=\"container my-4\">\r\n<div class=\"row justify-content-center\">\r\n<p class=\"text-white h4 text-center\">On occasion of Thanksgiving<br>Our restaurant will be closed on November 28th<br>Wishing you a joyful Thanksgiving!</p>\r\n</div>\r\n</div>','[]',0,0,0,0,'Order Indian Food Online | Maharaja Indian Cuisine Omaha','order indian food omaha, indian takeout omaha, takeout near me, food near me open now, maharaja indian cuisine online ordering','Enjoy authentic Indian food in Omaha with just a click! Order online from Maharaja Indian Cuisine for fresh curries, biryanis, and tandoori dishes',1,7,'2024-11-28 13:38:41','2025-08-18 11:43:05'),(15,'QR','qr','root','customurl','https://maharaja-mauve.vercel.app/',NULL,NULL,NULL,NULL,NULL,'<!-- Font Awesome Icons -->\r\n<div style=\"height: 100vh; display: flex; align-items: center; justify-content: center;\">\r\n<div style=\"width: 100%; max-width: 360px; padding: 20px; text-align: center;\"><!-- Title -->\r\n<h1 style=\"font-size: 28px; margin-bottom: 20px; letter-spacing: 1px;\">Maharaja</h1>\r\n<!-- View Menu Button --> <a style=\"display: block; width: 100%; padding: 16px; margin-bottom: 14px; background-color: #fd0200; color: #fff; text-decoration: none; border-radius: 10px; font-size: 17px; font-weight: 600; text-align: center;\" href=\"https://your-menu-link.com\"> View Menu </a> <!-- Give a Review Button --> <a style=\"display: block; width: 100%; padding: 16px; margin-bottom: 16px; background-color: #111; color: #fff; text-decoration: none; border-radius: 10px; font-size: 17px; font-weight: 600; text-align: center; border: 2px solid #fd0200;\" href=\"https://your-review-link.com\"> Give a Review </a> <!-- Social Icons -->\r\n<div style=\"display: flex; justify-content: center; gap: 26px; margin-top: 10px;\"><a style=\"width: 52px; height: 52px; background-color: #111; border-radius: 50%; display: flex; align-items: center; justify-content: center; color: #fd0200; font-size: 24px; text-decoration: none;\" href=\"https://instagram.com/yourpage\" target=\"_blank\" rel=\"noopener\" aria-label=\"Instagram\"> </a> <a style=\"width: 52px; height: 52px; background-color: #111; border-radius: 50%; display: flex; align-items: center; justify-content: center; color: #fd0200; font-size: 24px; text-decoration: none;\" href=\"https://tiktok.com/@yourpage\" target=\"_blank\" rel=\"noopener\" aria-label=\"TikTok\"> </a></div>\r\n</div>\r\n</div>','[]',0,0,0,1,NULL,NULL,NULL,1,NULL,'2026-01-13 18:07:48','2026-01-16 14:39:13');
