INSERT INTO `faqs` VALUES (1,1,'What types of events do you cater?','<p>We cater to a wide range of events, including weddings, corporate events, birthday parties, anniversaries, and more. Our catering services are perfect for any occasion in Omaha.</p>',NULL,NULL,0,1,'2024-11-19 06:27:01','2024-11-23 13:42:21'),(2,1,'How do I place a catering order?','<p>You can place a catering order by contacting us at [4025054488] or by filling out the form below. We will get in touch with you to confirm the details.</p>',NULL,NULL,0,2,'2024-11-23 13:34:01','2024-11-23 13:42:21'),(3,1,'Do you offer customized menus for special occasions?','<p>Yes, we offer customizable menus to suit your requirements and dietary needs.</p>',NULL,NULL,0,3,'2024-11-23 13:38:17','2024-11-23 13:42:21'),(4,1,'Can I arrange a tasting session before my event?','<p>Yes, we can arrange a tasting session only for the big events. Once the catering contract is finalized then you can schedule a tasting session by contacting us directly at [402-505-4488].</p>',NULL,NULL,0,7,'2024-11-23 13:38:52','2024-11-25 11:33:40'),(5,1,'Can you accommodate special dietary requirements?','<p>Absolutely! We can accommodate a variety of dietary requirements, including vegetarian, vegan, gluten-free, nut-free, and other specific needs. Please let us know your requirements when placing your order. Please mention if you have any allergies.</p>',NULL,NULL,0,4,'2024-11-23 13:39:40','2024-11-23 13:42:21'),(6,1,'How far in advance do I need to place a catering order?','<p>For small events (e.g., 1-2 trays), we can accept orders up to one day in advance. For larger events, we recommend placing your order 2- 3 weeks ahead. Please contact us at [402-505-4488] as early as possible to discuss your needs and availability to manage preparation time.</p>',NULL,NULL,0,5,'2024-11-23 13:41:09','2024-11-25 11:33:40'),(7,1,'What is included in your catering service?','<p>Our catering service includes food preparation, delivery, setup, and cleanup. We also provide necessary serving utensils, plates, and cutlery. Additional services, such as waitstaff and bartenders, can be arranged upon request.</p>',NULL,NULL,0,6,'2024-11-23 13:41:51','2024-11-25 11:33:40');
/*!40000 ALTER TABLE `faqs` ENABLE KEYS */;
UNLOCK TABLES;

