INSERT INTO `services` VALUES (3,2,'Authentic Indian Flavors','authentic-indian-flavors',NULL,'jpeg-optimizer_service1_a6227bsd5.png',NULL,'<p>Our chefs meticulously prepare each dish using traditional recipes and high-quality ingredients.</p>',NULL,NULL,1,'\"[]\"',NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,'2024-11-18 12:31:49','2024-11-26 06:10:20'),(4,2,'Customizable Menus','customizable-menus',NULL,'jpeg-optimizer_service2_sqpbzkv6r.png',NULL,'<p>We work closely with you to create a personalized menu that reflects your preferences and dietary needs.</p>',NULL,NULL,1,'\"[]\"',NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,'2024-11-18 12:36:22','2024-11-26 06:10:22'),(5,2,'Impeccable Service','impeccable-service',NULL,'service_3_h0rpbwjim.png',NULL,'<p>Our experienced staff will handle every aspect of your event, from setup to cleanup.</p>',NULL,NULL,1,'\"[]\"',NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,'2024-11-18 12:38:54','2024-11-26 06:10:23'),(6,2,'Stunning Presentation','stunning-presentation',NULL,'jpeg-optimizer_presenattion3_12flk987x.png',NULL,'<p>Our elegant presentation will impress your guests and elevate your event.</p>',NULL,NULL,1,'\"[]\"',NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,'2024-11-18 12:58:01','2024-11-26 06:10:24'),(7,2,'Different packages available','different-packages-available',NULL,'different_cat-(2)_7ysrsxq78.png',NULL,'<p>We can package the catering in the way you want, from just preparing the food to delivering it, or end-to-end setup to cleanup. It can be tailored to your needs.</p>',NULL,NULL,1,'\"[]\"',NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,'2024-11-18 13:13:09','2024-11-26 06:10:31'),(8,1,'Corporate Events','corporate-events',NULL,'service_3_darn1qv80.png',NULL,'<p>We provide exceptional food and the best catering services for business meetings, team gatherings, and client dinners. Our menu includes a variety of fresh and flavorful dishes to suit different preferences. From presentation to taste, everything is crafted to reflect the high standards of your event. Let us take care of the catering so you can focus on impressing your guests and building valuable connections. Make your corporate event a success with the best catering services near you!</p>',NULL,NULL,1,'\"[]\"',NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,'2024-11-19 06:22:16','2024-11-26 06:10:13'),(9,1,'Weddings','weddings',NULL,'Untitled-design_9igjix19o.jpg','weddings','<p>Your wedding day deserves the finest catering services. We offer a rich selection of authentic Indian delicacies, freshly prepared to delight your guests. From traditional wedding dishes to modern favorites, our menu is designed to suit your unique style. We take care of every detail, ensuring that the food complements the beauty of your special day. Whether you&rsquo;re hosting a grand reception or an intimate ceremony, our team provides a seamless experience. For the best wedding catering services near you, trust us to make your day unforgettable.</p>',NULL,NULL,1,'\"[]\"',NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,'2024-11-23 13:52:00','2024-11-26 06:10:14'),(10,1,'Birthday Parties','birthday-parties',NULL,'1_kcsgb6nrm.png','Birthday Parties','<p>Make your birthday party a hit with our catering services, known for delivering the best food for parties. Our menu includes a variety of flavorful dishes for kids, adults, and everyone in between. Whether you prefer classic comfort food or something unique, we tailor the menu to match your celebration. Our stunning presentation and fresh ingredients add a festive touch to the occasion. Celebrate with the best birthday party catering services near you and enjoy a hassle-free, fun-filled day!</p>',NULL,NULL,1,'\"[]\"',NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,'2024-11-24 06:42:22','2024-11-26 06:10:15'),(11,1,'Private Parties','private-parties',NULL,'2_uts7jjkxh.jpg','Private Parties','<p>Make your private party unforgettable with our customized catering services. Whether it&rsquo;s an anniversary, family reunion, or a casual get-together, we create menus tailored to your event. Our team prepares every dish using fresh, high-quality ingredients to ensure amazing taste and presentation. From elegant setups to seamless service, we handle every detail so you can relax and enjoy the occasion. Searching for private party catering near you? Let us bring the perfect mix of flavor and style to your celebration!</p>',NULL,NULL,1,'\"[]\"',NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,'2024-11-24 07:06:13','2024-11-26 06:10:16');
/*!40000 ALTER TABLE `services` ENABLE KEYS */;
UNLOCK TABLES;

