INSERT INTO `sliders` VALUES (2,'b1f-(2)_lb2y9wkw3.png','Traditional Indian Food in Omaha','Traditional<span> Indian Food</span> in Omaha','Experience the essence of India in Omaha! Explore authentic Traditional Indian Food, where every bite tells a flavorful tale. Satisfy your cravings with us!','Read More',NULL,0,1,1,'2023-12-27 03:31:25','2025-10-04 18:14:08'),(3,'b2f_9xb4xwbar.png','Chicken Tikka Masala in Omaha','Savor <span>Chicken Tikka</span> Masala Magic!','Savor the magic of Chicken Tikka Masala tender chicken, rich masala. A taste journey not to be missed. \r\nMust try now!','Read More',NULL,0,1,2,'2024-01-29 09:22:41','2025-10-04 18:53:53'),(4,'thali_8v2xcy2nu.webp','Indian Thali in Omaha','Weekend <span> Thalis </span>Await You!','The weekend just got better! Enjoy our delicious Indian thali, a mouthwatering blend of tastes all on one a plate. Enjoy the delectable simplicity of your weekend feast—don\'t miss it!','Read More',NULL,0,0,3,'2024-01-29 09:25:14','2024-08-12 05:20:33'),(5,'b3f-(1)_rc0p1jxmm.png','Bar facility in Omaha','Raise <span>The Bar</span>on Savings!','With our bar\'s cool vibes and hotter sips! From a wide drink selection to Indian specials, we\'ve crafted the perfect blend of chill and thrill. Join us – where every sip is an experience!','Read More',NULL,0,1,4,'2024-01-29 09:47:55','2025-10-04 19:54:06'),(6,'b4f_5lvwb75o8.png','Online order to your home delivery from Omaha','Quick & Tasty <span>Takeaway</span> Delights!','Order online for quick and tasty takeaways! Your favorite flavors, just a click away. Try it now','Order Now','https://maharajaindiancuisine.hungerrush.com/Order/OrderType',1,1,5,'2024-01-29 11:14:18','2026-02-11 08:16:10'),(9,'Untitled-design-(7)_4r0y91fz8.png','Father and children','Turn this <span> Father\'s Day</span> into a Royal Feast','Make Father’s Day special with a royal Indian meal and a free drink for Dad.\r\nDine-in only | Offer valid until June 16.','Call now!','tel:402-505-4488',0,0,NULL,'2025-06-10 15:48:43','2025-06-17 09:35:48');
