INSERT INTO `testimonials` VALUES (1,'Pauravi Gandhi',NULL,NULL,NULL,'unnamed_jb60xje75.png','Pauravi Gandhi',NULL,NULL,NULL,NULL,'<p>A good Indian food experience after a very long time in Omaha!&nbsp;Please retain the quality and we look forward to having more with you guys!</p>',NULL,0,1,'2024-01-19 07:09:48','2024-03-07 18:43:42',NULL),(2,'Jordyn Schnabel',NULL,NULL,NULL,'unnamed-(1)_mmcz3bnqj.png','Pauravi Gandhi',NULL,NULL,NULL,NULL,'<p>Prices are decent and slightly cheaper if you eat in the restaurant rather than online. Very authentic, everything was delicious.</p>',NULL,0,1,'2024-01-19 07:10:12','2024-03-07 18:43:50',NULL),(3,'Molly S',NULL,NULL,NULL,'molly-s_fhurhhe3g.png','Pauravi Gandhi',NULL,NULL,NULL,NULL,'<p>Best Indian food in Omaha! I&#39;ve tried others, but this is my top pick. Highly recommend for authentic flavors.</p>',NULL,0,1,'2024-01-19 07:10:36','2024-03-07 18:43:58',NULL),(4,'Jared Anderson',NULL,NULL,NULL,'unnamed-(2)_inpfiikfq.png','Pauravi Gandhi',NULL,NULL,NULL,NULL,'<p>This place has amazing food! Seems authentic. There&#39;s a big menu, so try a few visits to find what you like best!</p>',NULL,0,1,'2024-01-19 07:10:38','2024-03-07 18:44:06',NULL);
/*!40000 ALTER TABLE `testimonials` ENABLE KEYS */;
UNLOCK TABLES;

